// Ivybound pattern: flatten payload before splitInBatches.
const d = $input.first().json;
const event = d.event || {};
const sequence = d.sequence || {};
const attendees = d.attendees || [];

return attendees.map(a => ({
  json: {
    ...a,
    segment: sequence.segment || 'speaker',
    eventId: event.id,
    eventTitle: event.title,
    eventDate: event.event_date,
    triggeredAt: d.triggered_at,
  }
}));

const raw = $input.first().json.message?.content || '';
let parsed = { linkedinPost: raw };
try {
  const clean = raw.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {}
const d = $('Loop – One VIP at a Time').first().json;
return [{ json: { ...d, linkedinPost: parsed.linkedinPost || raw } }];
